output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?tournament ?tournamentLabel WHERE {
  ?tournament rdfs:label ?tournamentLabel .
  FILTER(LANG(?tournamentLabel) = 'en' && CONTAINS(LCASE(?tournamentLabel) , 'seascape sports club open'))
}

args.sparql:
SELECT ?player WHERE {
  ?player rdfs:label ?label .
  FILTER (LANG(?label) = 'en' && CONTAINS(LCASE(?label), 'john paul fruttero'))
  ?player wdt:P31 wd:Q5185755 .  # Human
  ?player wdt:P27 wd:Q30 .     # American
}
